        tags: { device_id: data.device_id },
        fields: {
            temperature: parseFloat(data.temperature),
            humidity:    parseFloat(data.humidity),
            pressure:    parseFloat(data.pressure),
            co2:         parseFloat(data.co2_ppm || data.co2 || 0),
            aqi:         parseFloat(data.aqi)
        },
        timestamp: new Date()
    }
];

node.log('Demo: ' + data.device_id + ' temp=' + data.temperature);
return msg;

